try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const business = $node['Split In Batches'].json;
    const feedData = item.json.data || [];
    const allComments = [];
    for (const post of feedData) {
      if (post.comments && post.comments.data) {
        for (const comment of post.comments.data) {
          allComments.push({
            comment_id: comment.id,
            message: comment.message,
            from: comment.from ? comment.from.name : 'Unknown',
            created_time: comment.created_time
          });
        }
      }
    }
    results.push({json: {
      business_id: business.id,
      business_name: business.business_name || '',
      email: business.email || '',
      comments: allComments.slice(0, 10),
      comment_count: allComments.length
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message, comments: [], business_id: $node['Split In Batches'].json.id}}];
}

