try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const responseContent = item.json.content && item.json.content[0] ? item.json.content[0].text : '[]';
    let parsed = [];
    try {
      parsed = JSON.parse(responseContent);
    } catch(e) {
      const match = responseContent.match(/\[[\s\S]*\]/);
      if (match) {
        try { parsed = JSON.parse(match[0]); } catch(e2) { parsed = []; }
      }
    }
    results.push({json: {
      business_id: $node['Parse Comments'].json['business_id'],
      business_name: $node['Parse Comments'].json['business_name'],
      email: $node['Parse Comments'].json['email'],
      replies: Array.isArray(parsed) ? parsed : [],
      comment_count: $node['Parse Comments'].json['comment_count']
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message, replies: [], email: $node['Parse Comments'].json['email']}}];
}

try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const replies = item.json.replies || [];
    let tableRows = '';
    for (const reply of replies) {
      tableRows += `<tr>
        <td style="padding:10px;border:1px solid #E5E7EB;background:#F9FAFB;">${reply.original_comment || 'N/A'}</td>
        <td style="padding:10px;border:1px solid #E5E7EB;">${reply.suggested_reply || 'N/A'}</td>
        <td style="padding:10px;border:1px solid #E5E7EB;text-align:center;"><span style="background:#EEF2FF;color:#4F46E5;padding:2px 8px;border-radius:12px;font-size:12px;">${reply.tone || 'professional'}</span></td>
      </tr>`;
    }
    const htmlBody = `<html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;padding:20px;">
<h1 style="color:#4F46E5;">Facebook Comment Replies for ${item.json.business_name}</h1>
<p>We found <strong>${item.json.comment_count}</strong> comments. Here are suggested replies for the top ${replies.length}:</p>
<table style="width:100%;border-collapse:collapse;margin:20px 0;">
<thead><tr>
<th style="padding:12px;background:#4F46E5;color:white;text-align:left;">Original Comment</th>
<th style="padding:12px;background:#4F46E5;color:white;text-align:left;">Suggested Reply</th>
<th style="padding:12px;background:#4F46E5;color:white;text-align:center;">Tone</th>
</tr></thead>
<tbody>${tableRows}</tbody>
</table>
<p style="color:#6B7280;font-size:12px;">Maroa.ai - AI-Powered Marketing Automation</p>
</body></html>`;
    results.push({json: {
      email: item.json.email,
      business_name: item.json.business_name,
      subject: `Suggested Replies for Your Facebook Comments - ${item.json.business_name}`,
      html_body: htmlBody,
      reply_count: replies.length
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message}}];
}
